 25	import { getName } from '@utils/crds/common/selectors';
 26	import { getPlanNetworkMapName, getPlanStorageMapName } from '@utils/crds/plans/selectors';
 27	import { getPlanURL } from '@utils/crds/plans/utils';
 28	import { isEmpty } from '@utils/helpers';
 29	
 30	import { PlanConditionType } from '../utils/constants';
 31	
 32	import TroubleshootMessage from './TroubleshootMessage';
 33	
 34	type PlanCriticalAlertProps = PropsWithChildren & {
 35	  plan: V1beta1Plan;
 36	  condition: V1beta1PlanStatusConditions | undefined;
 37	  storageMaps: V1beta1StorageMap[];
 38	  networkMaps: V1beta1NetworkMap[];
 39	  sourceStorages: InventoryStorage[];
 40	  sourceNetworks: InventoryNetwork[];
 41	};
 42	
 43	const PlanCriticalAlert: FC<PlanCriticalAlertProps> = ({
 44	  condition,
 45	  networkMaps,
 46	  plan,
 47	  sourceNetworks,
 48	  sourceStorages,
 49	  storageMaps,
 50	}) => {
 51	  const { t } = useTranslation();
 52	
 53	  const type = condition?.type as PlanConditionType;
 54	
 55	  const planStorageMapName = getPlanStorageMapName(plan);
 56	  const planNetworkMapName = getPlanNetworkMapName(plan);
 57	
 58	  const planStorageMap = useMemo(
 59	    () => storageMaps.find((map) => getName(map) === planStorageMapName),
 60	    [storageMaps, planStorageMapName],
 61	  );
 62	
 63	  const planNetworkMap = useMemo(
 64	    () => networkMaps.find((map) => getName(map) === planNetworkMapName),
 65	    [networkMaps, planNetworkMapName],
 66	  );
 67	
 68	  const missingStorage = useMemo(
 69	    () =>
 70	      sourceStorages.filter(
 71	        (src) => !planStorageMap?.spec?.map.some((map) => map.source.name === src.name),
 72	      ),
 73	    [planStorageMap, sourceStorages],
 74	  );
 75	
 76	  const missingNetworks = useMemo(
 77	    () =>
 78	      sourceNetworks.filter(
 79	        (src) => !planNetworkMap?.spec?.map.some((map) => map.source.name === src.name),
 80	      ),
 81	    [planNetworkMap, sourceNetworks],
 82	  );
 83	
 84	  if (isEmpty(condition)) return null;
 85	
 86	  const showList =
 87	    type === PlanConditionType.VMStorageNotMapped || type === PlanConditionType.VMNetworksNotMapped;
 88	
 89	  return (
 90	    <Alert title={t('The plan is not ready')} variant={AlertVariant.danger} isExpandable={showList}>
 91	      <Stack hasGutter>
 92	        <TextContent className="forklift-providers-list-header__alert">
 93	          <Text component={TextVariants.p}>
 94	            <SmartLinkify>{condition?.message ?? EMPTY_MSG}</SmartLinkify>
 95	            {condition?.message?.endsWith('.') ? ' ' : '. '}
 96	            <TroubleshootMessage planURL={getPlanURL(plan)} type={type} />
 97	          </Text>
 98	        </TextContent>
 99	        {showList && (
100	          <StackItem>
101	            <List>
102	              {type === PlanConditionType.VMStorageNotMapped &&
103	                missingStorage.map((storage) => (
104	                  <ListItem key={storage?.name}>{storage?.name}</ListItem>
105	                ))}
106	              {type === PlanConditionType.VMNetworksNotMapped &&
107	                missingNetworks.map((network) => (
108	                  <ListItem key={network?.name}>{network?.name}</ListItem>
109	                ))}
110	            </List>
111	          </StackItem>
112	        )}
113	      </Stack>
114	    </Alert>
115	  );
116	};
117	
118	export default PlanCriticalAlert;

